    {
      "name": "内容创作与编辑",
      "description": "协助创作各类内容，包括博客文章、社交媒体帖子、产品描述等，并提供编辑和优化建议。"
    },
    {
      "name": "技术文档生成",
      "description": "自动生成技术文档、API文档、用户手册等，确保文档的准确性和可读性。"
    },
    {
      "name": "实时信息查询",
      "description": "通过联网功能获取最新信息，提供实时新闻、市场数据、技术趋势等最新资讯。"
    },
    {
      "name": "多轮对话记忆",
      "description": "能够记住对话历史，在长对话中保持上下文连贯性，提供更自然的交互体验。"
    },
    {
      "name": "安全内容过滤",
      "description": "内置安全机制，能够识别和过滤不当内容，确保生成内容的安全性和合规性。"
    }
